def write_report(out,decision,m,rank):
    lines=[f"# {TASK}","","D96 maps the next post-D95 bottleneck and audits train-loop bridge readiness without broad architecture claims.","",f"- decision: `{decision['decision']}`",f"- next: `{decision['next']}`",f"- next breakpoint: `{m['next_breakpoint_name']}` ({m['next_breakpoint_score']:.3f})",f"- trainable surrogate ready: `{m['trainable_surrogate_ready']}`","","| rank | breakpoint | score | confidence |","| ---: | --- | ---: | ---: |"]
    for r in rank: lines.append(f"| {r['rank']} | {r['breakpoint_name']} | {r['score']:.3f} | {r['rank_confidence']:.3f} |")
    lines.extend(["","## Boundary","",BOUNDARY,""]); (out/"report.md").write_text("\n".join(lines),encoding="utf-8")

